requestTransformation.script:
const rows = Array.isArray(payload.ResultData)
  ? payload.ResultData
  : Array.isArray(payload.ThirdPartyResultDataList)
    ? payload.ThirdPartyResultDataList
    : [];

if (rows.length !== 1) {
  throw new Error('This example expects exactly one result row per request.');
}

const row = rows[0];
const externalTestCode = String(row.TestCode || row.TestId || row.ServiceId || '').trim();
if (!externalTestCode) {
  throw new Error('Missing external test code in inbound payload.');
}

const orderNumber = String(row.OrderNo || row.IntegrationOrderId || '').trim();
if (!orderNumber) {
  throw new Error('Missing order number in inbound payload.');
}

const paramName = String(row.TestName || row.NameToBePrinted || '').trim();
const paramValue = String(row.TestResult || row.ResultValue || '').trim();

return {
  sourceContext: {
    vendorCode: 'PATHKIND',
    externalTestCode,
  },
  orderNo: orderNumber,
  gridTestCode: null,
  gridTestName: null,
  sampleID: '',
  testId: '',
  observations: [
    {
      gridParamCode: externalTestCode,
      paramCode: '',
      paramName,
      paramValue,
    }
  ]
};
